const trigger = $('Start').first().json;
function shellQuote(s) {
  if (s === undefined || s === null) s = '';
  return "'" + String(s).replace(/'/g, "'\\''") + "'";
}
const parts = ['node', '/workspaces/bmad-playground/pipeline3/bin/planning-launch.mjs'];
if (trigger.planningRunId) parts.push('--planning-run-id=' + shellQuote(trigger.planningRunId));
if (trigger.mode) parts.push('--mode=' + shellQuote(trigger.mode));
if (trigger.instruction) parts.push('--instruction=' + shellQuote(trigger.instruction));
if (trigger.sessionId) parts.push('--session-id=' + shellQuote(trigger.sessionId));
return [{ json: { command: parts.join(' '), planningRunId: trigger.planningRunId, mode: trigger.mode } }];
